const cors = require("cors");
const yahooFinance = require("yahoo-finance2").default;

const app = express();
const PORT = 3000;

app.use(cors());
app.use(express.json());

function generateMockData(symbol) {
  const data = [];
  let price = 150 + Math.random() * 100;
  const start = new Date("2024-01-01");

  for (let i = 0; i < 365; i++) {
    const date = new Date(start);
    date.setDate(start.getDate() + i);
    if (date.getDay() === 0 || date.getDay() === 6) continue;

    price = price * (1 + (Math.random() - 0.48) * 0.02);
    data.push({
      date: date.toISOString(),
      close: parseFloat(price.toFixed(2)),
      volume: Math.floor(Math.random() * 10000000 + 1000000),
    });
  }

  return {
    ticker: symbol,
    name: `${symbol} Inc.`,
    data,
    currentPrice: data.length > 0 ? data[data.length - 1].close : null,
  };
}

app.get("/api/hello", (req, res) => {
  res.json({ message: "Hello from the backend!" });
});

const USE_MOCK = true;

app.get("/api/stock/:symbol", async (req, res) => {
  try {
    const symbol = req.params.symbol.toUpperCase();

    if (USE_MOCK) {
      return res.json(generateMockData(symbol));
    }

    const data = await yahooFinance.chart(symbol, {
      period1: "2024-01-01",
      interval: "1d",
    });
    const quotes = data.quotes;

    const companyName = data.meta?.shortName || symbol;

    const response = {
      ticker: symbol,
      name: companyName,
      data: quotes.map((q) => ({
        date: q.date,
        close: q.close,
        volume: q.volume,
      })),
      currentPrice: quotes.length > 0 ? quotes[quotes.length - 1].close : null,
    };

    console.log(response);
    res.json(response);
  } catch (err) {
    console.error(err);
    res.status(500).send("Error fetching stock data");
  }
});

app.listen(PORT, "0.0.0.0", () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

